(async () => {

  // ─── CONSTANTS ────────────────────────────────────────────────────────────

  const COLOR = {
    bg:        '#FFFFFF',
    textPrim:  '#111827',
    textSec:   '#6B7280',
    accent:    '#2563EB',
    border:    '#E5E7EB',
    chipBg:    '#F3F4F6',
    contactBg: '#F9FAFB',
  };

  const PHOTO_BASE64 = '';

  const CONTENT = {
    name:     'Christopher Romanyk',
    title:    'Systems Engineer & Marine Mechanic',
    tagline:  'Reformed software engineer turned marine mechanic — bridging digital systems and mechanical expertise across high-stakes environments.',
    email:    'chris@hahnsolo.ca',
    phone:    '709.749.3429',
    location: 'St. John\'s, NL',
    bio:      'A strategic technical leader with a rare combination of software product management experience and hands-on marine mechanical expertise. Background spans consumer products, fintech, sports tech, and maritime systems — with a consistent focus on cross-functional leadership and operational rigour.',
    skills:   ['Systems Engineering', 'Product Management', 'Marine Diesel', 'SOX Compliance', 'Cross-functional Leadership', 'Agile', 'Data Analysis', 'Team Leadership'],
    blog: [
      {
        category: 'Career',
        title:    'From PM to Oiler: What I Learned Crossing Industries and Oceans',
        date:     'March 2025',
        excerpt:  'Leaving a decade in tech to work in marine engineering wasn\'t a step back — it was a masterclass in systems thinking, humility, and the value of getting your hands dirty.',
      },
    ],
    experience: [
      {
        role:    'Sr. PMT Tech II / Product Manager',
        company: 'Amazon',
        desc:    'Led financial reconciliation systems and SOX compliance initiatives across global operations. Managed cross-functional engineering and operations teams to deliver high-reliability internal tooling.',
      },
      {
        role:    'Sr. Product Manager',
        company: 'Google — Global Business Organization',
        desc:    'Drove product strategy for the Global Business Organization, aligning technical roadmaps with international sales and operations requirements across multiple markets.',
      },
      {
        role:    'Sr. Product Manager',
        company: 'Synergy Sports / SportRadar',
        desc:    'Built and launched coaching analytics solutions adopted by professional sports franchises. Owned the full product lifecycle from discovery through delivery and growth.',
      },
      {
        role:    'Consumer Product Owner',
        company: 'PBSC / Lyft',
        desc:    'Owned consumer-facing bike-sharing product features for Lyft\'s North American fleet. Partnered with hardware, software, and ops teams to improve rider experience and fleet reliability.',
      },
    ],
  };

  // ─── FONT LOADING ─────────────────────────────────────────────────────────

  let FONT_FAMILY = 'Inter';
  let FONT_SEMIBOLD = 'SemiBold';

  try {
    await Promise.all([
      figma.loadFontAsync({ family: 'Inter', style: 'Regular' }),
      figma.loadFontAsync({ family: 'Inter', style: 'Medium' }),
      figma.loadFontAsync({ family: 'Inter', style: 'SemiBold' }),
      figma.loadFontAsync({ family: 'Inter', style: 'Bold' }),
    ]);
  } catch (e) {
    // Fallback to Roboto if Inter unavailable (Roboto has no SemiBold — map to Bold)
    FONT_FAMILY = 'Roboto';
    FONT_SEMIBOLD = 'Bold';
    await Promise.all([
      figma.loadFontAsync({ family: 'Roboto', style: 'Regular' }),
      figma.loadFontAsync({ family: 'Roboto', style: 'Medium' }),
      figma.loadFontAsync({ family: 'Roboto', style: 'Bold' }),
    ]);
  }

  // ─── HELPERS ──────────────────────────────────────────────────────────────

  function solidFill(hex) {
    const r = parseInt(hex.slice(1, 3), 16) / 255;
    const g = parseInt(hex.slice(3, 5), 16) / 255;
    const b = parseInt(hex.slice(5, 7), 16) / 255;
    return [{ type: 'SOLID', color: { r, g, b } }];
  }


  function base64ToBytes(b64) {
    const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/';
    const lookup = new Uint8Array(256);
    for (let i = 0; i < chars.length; i++) lookup[chars.charCodeAt(i)] = i;
    const cleaned = b64.replace(/[^A-Za-z0-9+/]/g, '');
    const len = cleaned.length;
    let bufLen = Math.floor(len * 3 / 4);
    if (b64[b64.length - 1] === '=') bufLen--;
    if (b64[b64.length - 2] === '=') bufLen--;
    const buf = new Uint8Array(bufLen);
    let p = 0;
    for (let i = 0; i < len; i += 4) {
      const a = lookup[cleaned.charCodeAt(i)];
      const b = lookup[cleaned.charCodeAt(i + 1)];
      const c = lookup[cleaned.charCodeAt(i + 2)];
      const d = lookup[cleaned.charCodeAt(i + 3)];
      buf[p++] = (a << 2) | (b >> 4);
      if (p < bufLen) buf[p++] = ((b & 15) << 4) | (c >> 2);
      if (p < bufLen) buf[p++] = ((c & 3) << 6) | d;
    }
    return buf;
  }

  function makeFrame(name, w, layoutMode, opts) {
    opts = opts || {};
    const f = figma.createFrame();
    f.name = name;
    f.fills = opts.fills !== undefined ? opts.fills : [];
    f.layoutMode = layoutMode || 'VERTICAL';
    f.primaryAxisSizingMode = opts.primaryAxis || 'AUTO';
    f.counterAxisSizingMode = opts.counterAxis || 'FIXED';
    if (w > 0) f.resize(w, f.height);
    f.paddingTop    = opts.pt || 0;
    f.paddingBottom = opts.pb || 0;
    f.paddingLeft   = opts.pl || 0;
    f.paddingRight  = opts.pr || 0;
    f.itemSpacing   = opts.gap || 0;
    f.primaryAxisAlignItems  = opts.mainAlign  || 'MIN';
    f.counterAxisAlignItems  = opts.crossAlign || 'MIN';
    if (opts.cornerRadius) f.cornerRadius = opts.cornerRadius;
    return f;
  }

  function makeText(content, style, size, colorHex, opts) {
    opts = opts || {};
    const t = figma.createText();
    const resolvedStyle = style === 'SemiBold' ? FONT_SEMIBOLD : style;
    t.fontName = { family: FONT_FAMILY, style: resolvedStyle };
    t.fontSize = size;
    if (opts.width) {
      t.textAutoResize = 'HEIGHT';
      t.resize(opts.width, t.height);
    } else {
      t.textAutoResize = 'WIDTH_AND_HEIGHT';
    }
    t.characters = content;
    t.fills = solidFill(colorHex);
    if (opts.lineHeight) t.lineHeight = { value: opts.lineHeight, unit: 'PIXELS' };
    if (opts.letterSpacing) t.letterSpacing = { value: opts.letterSpacing, unit: 'PERCENT' };
    if (opts.align) t.textAlignHorizontal = opts.align;
    if (opts.decoration) t.textDecoration = opts.decoration;
    return t;
  }

  function makeRect(w, h, colorHex, opts) {
    opts = opts || {};
    const r = figma.createRectangle();
    r.resize(w, h);
    r.fills = solidFill(colorHex);
    if (opts.cornerRadius) r.cornerRadius = opts.cornerRadius;
    return r;
  }

  function makeChip(label) {
    const chip = makeFrame('Chip', 0, 'HORIZONTAL', {
      primaryAxis: 'AUTO',
      counterAxis: 'AUTO',
      pl: 12, pr: 12, pt: 6, pb: 6,
      fills: solidFill(COLOR.chipBg),
      cornerRadius: 9999,
      crossAlign: 'CENTER',
    });
    chip.appendChild(makeText(label, 'Medium', 13, COLOR.textSec));
    return chip;
  }

  function appendSection(parent, section) {
    section.layoutAlign = 'STRETCH';
    section.primaryAxisSizingMode = 'AUTO';
    parent.appendChild(section);
  }

  // ─── ROOT FRAME ───────────────────────────────────────────────────────────

  const root = makeFrame('Resume — Landing Page', 1440, 'VERTICAL', {
    fills: solidFill(COLOR.bg),
    primaryAxis: 'AUTO',
    counterAxis: 'FIXED',
    gap: 0,
  });

  // ─── NAVIGATION ───────────────────────────────────────────────────────────

  function buildNavigation(parent) {
    const nav = figma.createFrame();
    nav.name = 'Navigation';
    nav.fills = solidFill(COLOR.bg);
    nav.layoutMode = 'HORIZONTAL';
    nav.primaryAxisSizingMode = 'FIXED';
    nav.counterAxisSizingMode = 'FIXED';
    nav.resize(1440, 72);
    nav.paddingLeft  = 80;
    nav.paddingRight = 80;
    nav.primaryAxisAlignItems = 'SPACE_BETWEEN';
    nav.counterAxisAlignItems = 'CENTER';

    nav.appendChild(makeText(CONTENT.name, 'Bold', 17, COLOR.textPrim));

    const links = makeFrame('Nav Links', 0, 'HORIZONTAL', {
      primaryAxis: 'AUTO',
      counterAxis: 'AUTO',
      gap: 36,
      crossAlign: 'CENTER',
    });
    ['About', 'Blog', 'Experience', 'Contact'].forEach(label => {
      links.appendChild(makeText(label, 'Regular', 15, COLOR.textSec));
    });
    nav.appendChild(links);

    nav.layoutAlign = 'STRETCH';
    parent.appendChild(nav);

    const divider = makeRect(1440, 1, COLOR.border);
    divider.layoutAlign = 'STRETCH';
    parent.appendChild(divider);
  }

  // ─── HERO ─────────────────────────────────────────────────────────────────

  function buildHero(parent) {
    const section = makeFrame('Hero', 1440, 'VERTICAL', {
      fills: solidFill(COLOR.bg),
      primaryAxis: 'AUTO',
      counterAxis: 'FIXED',
      pt: 120, pb: 120, pl: 80, pr: 80,
      gap: 20,
      crossAlign: 'CENTER',
      mainAlign: 'CENTER',
    });

    // Circular headshot photo
    const imgBytes = base64ToBytes(PHOTO_BASE64);
    const imgRef = figma.createImage(imgBytes);
    const avatar = figma.createEllipse();
    avatar.resize(140, 140);
    avatar.fills = [{ type: 'IMAGE', scaleMode: 'FILL', imageHash: imgRef.hash }];
    avatar.strokes = [{ type: 'SOLID', color: { r: 1, g: 1, b: 1 } }];
    avatar.strokeWeight = 4;
    avatar.strokeAlign = 'OUTSIDE';
    section.appendChild(avatar);

    // Name
    const name = makeText(CONTENT.name, 'Bold', 72, COLOR.textPrim, { align: 'CENTER' });
    name.textAlignHorizontal = 'CENTER';
    section.appendChild(name);

    // Title
    const title = makeText(CONTENT.title, 'Regular', 24, COLOR.textSec, { align: 'CENTER' });
    title.textAlignHorizontal = 'CENTER';
    section.appendChild(title);

    // Spacer
    const spacer = makeFrame('Spacer', 0, 'VERTICAL', { primaryAxis: 'AUTO', counterAxis: 'AUTO' });
    spacer.resize(1, 8);
    section.appendChild(spacer);

    // Tagline
    const tagline = makeText(CONTENT.tagline, 'Regular', 18, COLOR.textSec, {
      width: 680,
      lineHeight: 30,
      align: 'CENTER',
    });
    tagline.textAlignHorizontal = 'CENTER';
    section.appendChild(tagline);

    // Spacer
    const spacer2 = makeFrame('Spacer2', 0, 'VERTICAL', { primaryAxis: 'AUTO', counterAxis: 'AUTO' });
    spacer2.resize(1, 12);
    section.appendChild(spacer2);

    // CTA Button
    const btn = makeFrame('CTA Button', 0, 'HORIZONTAL', {
      primaryAxis: 'AUTO',
      counterAxis: 'AUTO',
      pl: 32, pr: 32, pt: 16, pb: 16,
      fills: solidFill(COLOR.accent),
      cornerRadius: 8,
      crossAlign: 'CENTER',
      mainAlign: 'CENTER',
    });
    btn.appendChild(makeText('Get in touch', 'SemiBold', 16, COLOR.bg));
    section.appendChild(btn);

    appendSection(parent, section);
  }

  // ─── ABOUT ────────────────────────────────────────────────────────────────

  function buildAbout(parent) {
    const section = makeFrame('About', 1440, 'VERTICAL', {
      fills: solidFill(COLOR.bg),
      primaryAxis: 'AUTO',
      counterAxis: 'FIXED',
      pt: 80, pb: 80, pl: 80, pr: 80,
      gap: 48,
    });

    // Section heading
    section.appendChild(makeText('About', 'Bold', 32, COLOR.textPrim));

    // Divider line under heading
    const headDivider = makeRect(80, 3, COLOR.accent);
    headDivider.cornerRadius = 2;
    section.appendChild(headDivider);

    // Two-column row
    const row = makeFrame('About Row', 1280, 'HORIZONTAL', {
      primaryAxis: 'AUTO',
      counterAxis: 'AUTO',
      gap: 80,
    });

    // Left: Bio
    const bio = makeText(CONTENT.bio, 'Regular', 16, COLOR.textSec, {
      width: 560,
      lineHeight: 28,
    });
    row.appendChild(bio);

    // Right: Skills grid
    const skillsCol = makeFrame('Skills Column', 0, 'VERTICAL', {
      primaryAxis: 'AUTO',
      counterAxis: 'AUTO',
      gap: 16,
    });

    const skillsLabel = makeText('Core Skills', 'SemiBold', 14, COLOR.textPrim);
    skillsCol.appendChild(skillsLabel);

    const grid = makeFrame('Skills Grid', 560, 'HORIZONTAL', {
      primaryAxis: 'AUTO',
      counterAxis: 'AUTO',
      gap: 8,
    });
    grid.layoutWrap = 'WRAP';
    grid.counterAxisSpacing = 8;
    CONTENT.skills.forEach(s => grid.appendChild(makeChip(s)));
    skillsCol.appendChild(grid);

    row.appendChild(skillsCol);
    section.appendChild(row);

    appendSection(parent, section);
  }

  // ─── BLOG ─────────────────────────────────────────────────────────────────

  function buildBlog(parent) {
    const section = makeFrame('Blog', 1440, 'VERTICAL', {
      fills: solidFill(COLOR.bg),
      primaryAxis: 'AUTO',
      counterAxis: 'FIXED',
      pt: 80, pb: 80, pl: 80, pr: 80,
      gap: 48,
    });

    section.appendChild(makeText('Blog', 'Bold', 32, COLOR.textPrim));

    const headDivider = makeRect(80, 3, COLOR.accent);
    headDivider.cornerRadius = 2;
    section.appendChild(headDivider);

    const cardsCol = makeFrame('Blog Cards', 1280, 'VERTICAL', {
      primaryAxis: 'AUTO',
      counterAxis: 'FIXED',
      gap: 24,
    });

    CONTENT.blog.forEach(function(post) {
      const card = makeFrame('Blog Card', 1280, 'VERTICAL', {
        primaryAxis: 'AUTO',
        counterAxis: 'FIXED',
        pt: 32, pb: 32, pl: 32, pr: 32,
        gap: 12,
        fills: solidFill(COLOR.bg),
        cornerRadius: 12,
      });
      card.strokes = [{ type: 'SOLID', color: { r: 229/255, g: 231/255, b: 235/255 } }];
      card.strokeWeight = 1;
      card.strokeAlign = 'INSIDE';

      card.appendChild(makeText(post.category, 'SemiBold', 13, COLOR.accent));
      card.appendChild(makeText(post.title, 'Bold', 18, COLOR.textPrim, { width: 1216, lineHeight: 28 }));
      card.appendChild(makeRect(1216, 1, COLOR.border));
      card.appendChild(makeText(post.excerpt, 'Regular', 15, COLOR.textSec, { width: 1216, lineHeight: 24 }));
      card.appendChild(makeText(post.date, 'Regular', 13, COLOR.textSec));

      cardsCol.appendChild(card);
    });

    section.appendChild(cardsCol);
    appendSection(parent, section);
  }

  // ─── EXPERIENCE ───────────────────────────────────────────────────────────

  function buildJobCard(exp, cardWidth) {
    const card = makeFrame('Job Card — ' + exp.company, cardWidth, 'VERTICAL', {
      primaryAxis: 'AUTO',
      counterAxis: 'FIXED',
      pt: 32, pb: 32, pl: 32, pr: 32,
      gap: 12,
      fills: solidFill(COLOR.bg),
      cornerRadius: 12,
    });
    card.strokes = [{ type: 'SOLID', color: { r: 229/255, g: 231/255, b: 235/255 } }];
    card.strokeWeight = 1;
    card.strokeAlign = 'INSIDE';

    card.appendChild(makeText(exp.role, 'Bold', 18, COLOR.textPrim));
    card.appendChild(makeText(exp.company, 'SemiBold', 14, COLOR.accent));

    const divider = makeRect(cardWidth - 64, 1, COLOR.border);
    card.appendChild(divider);

    card.appendChild(makeText(exp.desc, 'Regular', 15, COLOR.textSec, {
      width: cardWidth - 64,
      lineHeight: 24,
    }));

    return card;
  }

  function buildExperience(parent) {
    const section = makeFrame('Experience', 1440, 'VERTICAL', {
      fills: solidFill(COLOR.bg),
      primaryAxis: 'AUTO',
      counterAxis: 'FIXED',
      pt: 80, pb: 80, pl: 80, pr: 80,
      gap: 48,
    });

    section.appendChild(makeText('Experience', 'Bold', 32, COLOR.textPrim));

    const headDivider = makeRect(80, 3, COLOR.accent);
    headDivider.cornerRadius = 2;
    section.appendChild(headDivider);

    const cardsCol = makeFrame('Cards', 1280, 'VERTICAL', {
      primaryAxis: 'AUTO',
      counterAxis: 'FIXED',
      gap: 24,
    });

    CONTENT.experience.forEach(exp => {
      cardsCol.appendChild(buildJobCard(exp, 1280));
    });

    section.appendChild(cardsCol);
    appendSection(parent, section);
  }

  // ─── CONTACT ──────────────────────────────────────────────────────────────

  function buildContact(parent) {
    const section = makeFrame('Contact', 1440, 'VERTICAL', {
      fills: solidFill(COLOR.contactBg),
      primaryAxis: 'AUTO',
      counterAxis: 'FIXED',
      pt: 80, pb: 80, pl: 80, pr: 80,
      gap: 24,
      crossAlign: 'CENTER',
      mainAlign: 'CENTER',
    });

    const heading = makeText('Get in Touch', 'Bold', 32, COLOR.textPrim, { align: 'CENTER' });
    heading.textAlignHorizontal = 'CENTER';
    section.appendChild(heading);

    const headDivider = makeRect(80, 3, COLOR.accent);
    headDivider.cornerRadius = 2;
    section.appendChild(headDivider);

    const sub = makeText(
      'Open to new opportunities and interesting projects. Feel free to reach out.',
      'Regular', 16, COLOR.textSec, { width: 560, lineHeight: 28, align: 'CENTER' }
    );
    sub.textAlignHorizontal = 'CENTER';
    section.appendChild(sub);

    // Spacer
    const spacer = makeFrame('Spacer', 1, 'VERTICAL', { primaryAxis: 'AUTO', counterAxis: 'AUTO' });
    spacer.resize(1, 8);
    section.appendChild(spacer);

    // Contact details row
    const contactRow = makeFrame('Contact Row', 0, 'HORIZONTAL', {
      primaryAxis: 'AUTO',
      counterAxis: 'AUTO',
      gap: 48,
      crossAlign: 'CENTER',
    });

    const emailText = makeText(CONTENT.email, 'SemiBold', 16, COLOR.accent, { decoration: 'UNDERLINE' });
    emailText.hyperlink = { type: 'URL', value: 'mailto:' + CONTENT.email };
    contactRow.appendChild(emailText);

    const separator = makeText('·', 'Regular', 16, COLOR.border);
    contactRow.appendChild(separator);

    contactRow.appendChild(makeText(CONTENT.phone, 'Regular', 16, COLOR.textSec));

    section.appendChild(contactRow);
    appendSection(parent, section);
  }

  // ─── FOOTER ───────────────────────────────────────────────────────────────

  function buildFooter(parent) {
    const topBorder = makeRect(1440, 1, COLOR.border);
    topBorder.layoutAlign = 'STRETCH';
    parent.appendChild(topBorder);

    const footer = figma.createFrame();
    footer.name = 'Footer';
    footer.fills = solidFill(COLOR.bg);
    footer.layoutMode = 'HORIZONTAL';
    footer.primaryAxisSizingMode = 'FIXED';
    footer.counterAxisSizingMode = 'FIXED';
    footer.resize(1440, 72);
    footer.paddingLeft  = 80;
    footer.paddingRight = 80;
    footer.primaryAxisAlignItems = 'SPACE_BETWEEN';
    footer.counterAxisAlignItems = 'CENTER';

    footer.appendChild(makeText('© 2025 Christopher Romanyk. All rights reserved.', 'Regular', 13, COLOR.textSec));
    footer.appendChild(makeText(CONTENT.location, 'Regular', 13, COLOR.textSec));

    footer.layoutAlign = 'STRETCH';
    parent.appendChild(footer);
  }

  // ─── ASSEMBLE ─────────────────────────────────────────────────────────────

  buildNavigation(root);
  buildHero(root);
  buildAbout(root);
  buildBlog(root);
  buildExperience(root);
  buildContact(root);
  buildFooter(root);

  figma.currentPage.appendChild(root);
  figma.viewport.scrollAndZoomIntoView([root]);
  figma.closePlugin();

})();
